class CreditCard {
  final String number;
  final String expiryMonth;
  final String expiryYear;
  final String cvv;
  final String? cardholderName;
  
  CreditCard({
    required this.number,
    required this.expiryMonth,
    required this.expiryYear,
    required this.cvv,
    this.cardholderName,
  });
  
  bool isValid() {
    return _validateCardNumber() && 
           _validateExpiry() && 
           _validateCVV();
  }
  
  bool _validateCardNumber() {
    final cleaned = number.replaceAll(RegExp(r'\s+'), '');
    if (cleaned.length < 13 || cleaned.length > 19) return false;
    
    int sum = 0;
    bool alternate = false;
    
    for (int i = cleaned.length - 1; i >= 0; i--) {
      int digit = int.parse(cleaned[i]);
      
      if (alternate) {
        digit *= 2;
        if (digit > 9) digit -= 9;
      }
      
      sum += digit;
      alternate = !alternate;
    }
    
    return sum % 10 == 0;
  }
  
  bool _validateExpiry() {
    final month = int.tryParse(expiryMonth);
    final year = int.tryParse(expiryYear);
    
    if (month == null || year == null) return false;
    if (month < 1 || month > 12) return false;
    
    final now = DateTime.now();
    final fullYear = year < 100 ? 2000 + year : year;
    final expiry = DateTime(fullYear, month + 1, 0);
    
    return expiry.isAfter(now);
  }
  
  bool _validateCVV() {
    return cvv.length >= 3 && cvv.length <= 4 && int.tryParse(cvv) != null;
  }
  
  String get maskedNumber {
    final cleaned = number.replaceAll(RegExp(r'\s+'), '');
    if (cleaned.length < 4) return cleaned;
    return '*' * (cleaned.length - 4) + cleaned.substring(cleaned.length - 4);
  }
  
  Map<String, String> toTokenizedData() {
    return {
      'number': _encryptData(number),
      'exp_month': expiryMonth,
      'exp_year': expiryYear,
      'cvc': _encryptData(cvv),
    };
  }
  
  String _encryptData(String data) {
    final bytes = utf8.encode(data);
    final hash = sha256.convert(bytes);
    return hash.toString();
  }
}

