  Future<PaymentResult> processPayPalPayment({
    required double amount,
    required String currency,
    String? customerId,
    Map<String, dynamic>? metadata,
  }) async {
    try {
      final accessToken = await _getPayPalAccessToken();
      if (accessToken == null) {
        return PaymentResult(
          success: false,
          message: 'PayPal authentication failed',
          status: TransactionStatus.failed,
        );
      }
      
      final payment = await _createPayPalPayment(
        accessToken: accessToken,
        amount: amount,
        currency: currency,
        metadata: metadata,
      );
      
      if (payment == null) {
        return PaymentResult(
          success: false,
          message: 'PayPal payment creation failed',
          status: TransactionStatus.failed,
        );
      }
      
      final approvalUrl = payment['links']?.firstWhere(
        (link) => link['rel'] == 'approval_url',
        orElse: () => null,
      )?['href'];
      
      if (approvalUrl == null) {
        return PaymentResult(
          success: false,
          message: 'PayPal approval URL not found',
          status: TransactionStatus.failed,
        );
      }
      
      final transaction = Transaction(
        id: payment['id'],
        amount: amount,
        currency: currency,
        method: PaymentMethod.paypal,
        gateway: PaymentGateway.paypal,
        status: TransactionStatus.pending,
        timestamp: DateTime.now(),
        customerId: customerId,
        metadata: metadata,
      );
      
      _addTransaction(transaction);
      
      return PaymentResult(
        success: true,
        transactionId: payment['id'],
        message: 'PayPal payment initiated',
        status: TransactionStatus.pending,
        metadata: {'approval_url': approvalUrl},
      );
      
    } catch (e) {
      return PaymentResult(
        success: false,
        message: 'PayPal error: ${e.toString()}',
        status: TransactionStatus.failed,
      );
    }
  }
  
  Future<String?> _getPayPalAccessToken() async {
    try {
      final credentials = base64.encode(
        utf8.encode('${config.paypalClientId}:${config.paypalSecret}'),
      );
      
      final baseUrl = config.environment == 'production'
          ? 'https://api.paypal.com'
          : 'https://api.sandbox.paypal.com';
      
      final response = await http.post(
        Uri.parse('$baseUrl/v1/oauth2/token'),
        headers: {
          'Authorization': 'Basic $credentials',
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: 'grant_type=client_credentials',
      );
      
      if (response.statusCode == 200) {
        final data = json.decode(response.body);
        return data['access_token'];
      }
      
      return null;
    } catch (e) {
      debugPrint('PayPal token error: $e');
      return null;
    }
  }
  
  Future<Map<String, dynamic>?> _createPayPalPayment({
    required String accessToken,
    required double amount,
    required String currency,
    Map<String, dynamic>? metadata,
  }) async {
    try {
      final baseUrl = config.environment == 'production'
          ? 'https://api.paypal.com'
          : 'https://api.sandbox.paypal.com';
      
      final response = await http.post(
        Uri.parse('$baseUrl/v1/payments/payment'),
        headers: {
          'Authorization': 'Bearer $accessToken',
          'Content-Type': 'application/json',
        },
        body: json.encode({
          'intent': 'sale',
          'payer': {'payment_method': 'paypal'},
          'transactions': [
            {
              'amount': {
                'total': amount.toStringAsFixed(2),
                'currency': currency,
              },
              'description': metadata?['description'] ?? 'Payment',
            }
          ],
          'redirect_urls': {
            'return_url': metadata?['return_url'] ?? 'https://example.com/return',
            'cancel_url': metadata?['cancel_url'] ?? 'https://example.com/cancel',
          },
        }),
      );
      
      if (response.statusCode == 201) {
        return json.decode(response.body);
      }
      
      return null;
    } catch (e) {
      debugPrint('PayPal payment error: $e');
      return null;
    }
  }
  
