  Future<PaymentResult> refundTransaction({
    required String transactionId,
    double? amount,
    String? reason,
  }) async {
    try {
      final transaction = _transactionHistory.firstWhere(
        (t) => t.id == transactionId,
        orElse: () => throw Exception('Transaction not found'),
      );
      
      if (transaction.gateway == PaymentGateway.stripe) {
        return await _refundStripeTransaction(
          transactionId: transactionId,
          amount: amount,
          reason: reason,
        );
      } else if (transaction.gateway == PaymentGateway.paypal) {
        return await _refundPayPalTransaction(
          transactionId: transactionId,
          amount: amount,
          reason: reason,
        );
      }
      
      return PaymentResult(
        success: false,
        message: 'Refund not supported for this gateway',
        status: TransactionStatus.failed,
      );
      
    } catch (e) {
      return PaymentResult(
        success: false,
        message: 'Refund error: ${e.toString()}',
        status: TransactionStatus.failed,
      );
    }
  }
  
