    }
  }
  
  void _addTransaction(Transaction transaction) {
    _transactionHistory.add(transaction);
    _transactionController.add(transaction);
  }
  
  void _updateTransactionStatus(String transactionId, TransactionStatus status) {
    final index = _transactionHistory.indexWhere((t) => t.id == transactionId);
    if (index != -1) {
      final updated = Transaction(
        id: _transactionHistory[index].id,
        amount: _transactionHistory[index].amount,
        currency: _transactionHistory[index].currency,
        method: _transactionHistory[index].method,
        gateway: _transactionHistory[index].gateway,
        status: status,
        timestamp: _transactionHistory[index].timestamp,
        customerId: _transactionHistory[index].customerId,
        metadata: _transactionHistory[index].metadata,
      );
      
      _transactionHistory[index] = updated;
      _transactionController.add(updated);
    }
  }
  
  Future<Transaction?> getTransaction(String transactionId) async {
    try {
      return _transactionHistory.firstWhere((t) => t.id == transactionId);
    } catch (e) {
      return null;
    }
  }
  
  List<Transaction> getTransactionsByCustomer(String customerId) {
    return _transactionHistory.where((t) => t.customerId == customerId).toList();
  }
  
  List<Transaction> getTransactionsByStatus(TransactionStatus status) {
    return _transactionHistory.where((t) => t.status == status).toList();
  }
  
  double getTotalRevenue({String? customerId}) {
    return _transactionHistory
        .where((t) =>
            t.status == TransactionStatus.completed &&
            (customerId == null || t.customerId == customerId))
        .fold(0.0, (sum, t) => sum + t.amount);
  }
  
  void dispose() {
    _transactionController.close();
  }
}

class InAppPurchaseService {
  static const platform = MethodChannel('payment_processing/iap');
  final StreamController<Transaction> _purchaseController = StreamController.broadcast();
  
  Stream<Transaction> get purchaseStream => _purchaseController.stream;
  
  Future<bool> initialize() async {
    try {
      final result = await platform.invokeMethod('initialize');
      return result as bool;
    } catch (e) {
      debugPrint('IAP initialization error: $e');
      return false;
    }
  }
  
  Future<List<Product>> getProducts(List<String> productIds) async {
    try {
      final result = await platform.invokeMethod('getProducts', {
        'productIds': productIds,
      });
      
      final products = (result as List).map((item) {
        return Product.fromMap(Map<String, dynamic>.from(item));
      }).toList();
      
      return products;
    } catch (e) {
      debugPrint('Get products error: $e');
      return [];
    }
  }
  
  Future<PaymentResult> purchaseProduct(String productId) async {
    try {
      final result = await platform.invokeMethod('purchase', {
        'productId': productId,
      });
      
      if (result['success'] == true) {
        final transaction = Transaction(
          id: result['transactionId'],
          amount: result['amount'].toDouble(),
          currency: result['currency'],
          method: PaymentMethod.inAppPurchase,
          gateway: Platform.isIOS ? PaymentGateway.appStore : PaymentGateway.playStore,
          status: TransactionStatus.completed,
          timestamp: DateTime.now(),
          metadata: {'productId': productId},
        );
        
        _purchaseController.add(transaction);
        
        return PaymentResult(
          success: true,
          transactionId: result['transactionId'],
          message: 'Purchase successful',
          status: TransactionStatus.completed,
        );
      }
      
      return PaymentResult(
        success: false,
        message: result['error'] ?? 'Purchase failed',
        status: TransactionStatus.failed,
      );
      
    } catch (e) {
      return PaymentResult(
        success: false,
        message: 'Purchase error: ${e.toString()}',
        status: TransactionStatus.failed,
      );
    }
  }
  
  Future<PaymentResult> restorePurchases() async {
    try {
      final result = await platform.invokeMethod('restore');
      
      if (result['success'] == true) {
        return PaymentResult(
          success: true,
          message: 'Purchases restored',
          status: TransactionStatus.completed,
          metadata: result,
        );
      }
      
      return PaymentResult(
        success: false,
        message: 'Restore failed',
        status: TransactionStatus.failed,
      );
      
    } catch (e) {
      return PaymentResult(
        success: false,
        message: 'Restore error: ${e.toString()}',
        status: TransactionStatus.failed,
      );
    }
  }
  
  void dispose() {
    _purchaseController.close();
  }
}

class Product {
  final String id;
  final String title;
  final String description;
  final double price;
  final String currency;
  
  Product({
    required this.id,
    required this.title,
    required this.description,
    required this.price,
    required this.currency,
  });
  
  factory Product.fromMap(Map<String, dynamic> map) => Product(
    id: map['id'],
    title: map['title'],
    description: map['description'],
    price: map['price'].toDouble(),
    currency: map['currency'],
  );
}

class SecurityUtils {
  static String generateTransactionId() {
    final timestamp = DateTime.now().millisecondsSinceEpoch;
    final random = List.generate(16, (_) => (timestamp % 256).toRadixString(16));
    return '${timestamp}_${random.join()}';
  }
  
  static String hashSensitiveData(String data) {
    final bytes = utf8.encode(data);
    final hash = sha256.convert(bytes);
    return hash.toString();
  }
  
  static bool validateAmount(double amount) {
    return amount > 0 && amount < 1000000;
  }
  
  static bool validateCurrency(String currency) {
    const validCurrencies = ['USD', 'EUR', 'GBP', 'JPY', 'CAD', 'AUD'];
    return validCurrencies.contains(currency.toUpperCase());
  }
}